/**
 * @name SecurityWrapperResponse sendError/setStatus message source analysis
 * @description Determine what string value is passed to sendError/setStatus in SecurityWrapperResponse
 * @kind path-problem
 * @problem.severity error
 * @id java/security-wrapper-sendError-taint
 * @tags security
 *       external/cwe/cwe-079
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module SendErrorConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Any parameter to sendError or setStatus in SecurityWrapperResponse
    exists(Method m |
      m.getDeclaringType().hasQualifiedName("org.owasp.esapi.filters", "SecurityWrapperResponse") and
      (m.hasName("sendError") or m.hasName("setStatus")) and
      source.asParameter() = m.getAParameter() and
      source.asParameter().getType() instanceof TypeString
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // Flows into calls to super.sendError with message argument
    exists(MethodCall mc |
      mc.getMethod().hasName("sendError") and
      mc.getEnclosingCallable().getDeclaringType().hasQualifiedName("org.owasp.esapi.filters", "SecurityWrapperResponse") and
      sink.asExpr() = mc.getArgument(1)
    )
  }
}

module SendErrorFlow = TaintTracking::Global<SendErrorConfig>;
import SendErrorFlow::PathGraph

from SendErrorFlow::PathNode source, SendErrorFlow::PathNode sink
where SendErrorFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Unencoded string from $@ passed to sendError without HTML encoding", source.getNode(), "parameter"

