/**
 * @name SecurityWrapperResponse - setStatus(int,String) passes raw message to sendError
 * @description The deprecated setStatus(int sc, String sm) method passes its sm parameter directly to 
 *              sendError without HTML encoding, allowing XSS if callers pass user-controlled messages
 * @kind path-problem
 * @problem.severity error
 * @id java/security-wrapper-setstatus-xss-confirmed
 * @tags security
 *       external/cwe/cwe-079
 *       external/cwe/cwe-116
 */

import java
import semmle.code.java.dataflow.TaintTracking

module SetStatusXSSConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // The String sm parameter of SecurityWrapperResponse.setStatus(int, String)
    exists(Method m, Parameter p |
      m.getDeclaringType().hasQualifiedName("org.owasp.esapi.filters", "SecurityWrapperResponse") and
      m.hasName("setStatus") and
      m.getNumberOfParameters() = 2 and
      p = m.getAParameter() and
      p.getType() instanceof TypeString and
      source.asParameter() = p
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // Flows into the second argument of any sendError call (the message argument)
    exists(MethodCall mc |
      mc.getMethod().hasName("sendError") and
      mc.getNumArgument() >= 2 and
      mc.getEnclosingCallable().getDeclaringType().hasQualifiedName("org.owasp.esapi.filters", "SecurityWrapperResponse") and
      sink.asExpr() = mc.getArgument(1)
    )
  }

  // No HTML encoding is applied
  predicate isBarrier(DataFlow::Node node) {
    exists(MethodCall mc |
      (mc.getMethod().hasName("encodeForHTML") or
       mc.getMethod().hasName("encodeForHTMLAttribute") or
       mc.getMethod().hasName("htmlEscape") or
       mc.getMethod().hasName("escapeHtml")) and
      node.asExpr() = mc
    )
  }
}

